import { type ReactNode } from 'react';
import type { AnnotationsMarkerConfig, BaseMarkerProps, NumericalMarkerProps } from './annotations-marker-props.js';
import type { AnnotationsTrackConfig } from './annotations-track-props.js';
import type { IndicatorsDisplay } from '../components/indicators/types.js';
/** @internal */
export type NumericalAnnotationsMarkerConfig = AnnotationsMarkerConfig & NumericalMarkerProps & {
    indicatorsDisplay?: IndicatorsDisplay;
};
/** @internal */
export type NumericalAnnotationsTrackConfig = AnnotationsTrackConfig & {
    markers: NumericalAnnotationsMarkerConfig[];
    annotationsActions?: (annotation: BaseMarkerProps & NumericalMarkerProps & {
        indicatorsDisplay?: IndicatorsDisplay;
    }) => ReactNode;
    indicatorsDisplay?: IndicatorsDisplay;
};
